        if (h - l < 20) { insertion_sort(arr, l, h); return; }
        int p = partition(arr, l, h);
        if (p - l < h - p) { quicksort(arr, l, p); l = p + 1; }
        else { quicksort(arr, p + 1, h); h = p; }
    }
}

int partition(std::vector<int>& a, int l, int h) {
    int m = l + (h - l) / 2;
    if (a[m] < a[l]) std::swap(a[m], a[l]);
    if (a[h] < a[l]) std::swap(a[h], a[l]);
    if (a[h] < a[m]) std::swap(a[h], a[m]);
    int p = a[m], i = l - 1, j = h + 1;
